 1	import * as React from 'react';
 2	
 3	import { SplitItem } from '@patternfly/react-core';
 4	
 5	import * as argoIcon from '../../images/argo.png';
 6	import ExternalLink from '../utils/ExternalLink/ExternalLink';
 7	
 8	type ArgoCdLinkProps = {
 9	  envName: string;
10	  appName: string;
11	  argocdLink: any;
12	};
13	
14	const ArgoCdLink: React.FC<ArgoCdLinkProps> = ({ envName, appName, argocdLink }) => {
15	  // Use environment name as is or the original KAM-based design
16	  const appNameLink = envName.includes(appName) ? envName : envName + '-' + appName;
17	  return (
18	    <SplitItem className="gitops-plugin__environment-details__env-section__deployment-history__argocd-link">
19	      <ExternalLink href={`${argocdLink.spec.href}/applications/${appNameLink}`}>
20	        <span className="gitops-plugin__environment-details__env-section__argo-external-link">
21	          <img loading="lazy" src={argoIcon} alt="Argo CD" width="19px" height="24px" />
22	        </span>
23	      </ExternalLink>
24	    </SplitItem>
25	  );
26	};
27	
28	export default ArgoCdLink;

